def triangle_max(t):
    n = len(t)
    dp = [row[:] for row in t]
    for i in range(1, n):
        for j in range(i + 1):
            if j == 0:
                dp[i][j] += dp[i-1][0]
            elif j == i:
                dp[i][j] += dp[i-1][j-1]
            else:
                dp[i][j] += max(dp[i-1][j-1], dp[i-1][j])
    return max(dp[-1])

